// Node.js: simple semaphore without external deps
class Semaphore {
  constructor(max) { this.max = max; this.count = 0; this.queue = []; }
  async acquire() {
    if (this.count < this.max) { this.count++; return; }
    return new Promise((res, rej) => {
      this.queue.push(res);
    });
  }
  release() {
    if (this.queue.length > 0) { const next = this.queue.shift(); next(); }
    else { this.count--; }
  }
}

const s = new Semaphore(5);

async function handler(req, res) {
  try {
    const t = s.acquire();
    const timeout = setTimeout(() => { /* optional max wait */ }, 1000);
    await t;
    clearTimeout(timeout);
    // do work
    res.end('ok');
  } catch (e) {
    res.statusCode = 503; res.end('busy');
  } finally {
    s.release();
  }
}
